    private fun validateIntent(intent: Intent?): Boolean {
        if (intent == null) {
            Log.w(TAG, "Null intent received")
            return false
        }

        val action = intent.action
        if (action != Intent.ACTION_SEND && action != Intent.ACTION_SEND_MULTIPLE) {
            Log.w(TAG, "Unexpected action: $action")
            return false
        }

        val type = intent.type
        if (type.isNullOrBlank()) {
            Log.w(TAG, "Null or blank MIME type")
            return false
        }

        // Validate MIME type is one we expect
        if (!type.startsWith("text/") && !type.startsWith("image/")) {
            Log.w(TAG, "Unexpected MIME type: $type")
            return false
        }

        // Check for intent URI injection
        if (intent.dataString?.contains("intent:") == true ||
            intent.dataString?.contains("javascript:") == true
        ) {
            Log.w(TAG, "Potential intent/javascript URI injection detected")
            return false
        }

        return true
    }

    private fun handleIncomingIntent(intent: Intent) {
        when (intent.action) {
            Intent.ACTION_SEND -> {
                val type = intent.type ?: return
                when {
                    type.startsWith("text/") -> handleSharedText(intent)
                    type.startsWith("image/") -> handleSharedImage(intent)
                    else -> {
                        Log.w(TAG, "Unsupported MIME type: $type")
                        showError("Unsupported content type")
                    }
                }
            }
            Intent.ACTION_SEND_MULTIPLE -> {
                val type = intent.type ?: return
                if (type.startsWith("image/")) {
                    handleSharedMultipleImages(intent)
                } else {
                    Log.w(TAG, "Unsupported MIME type for SEND_MULTIPLE: $type")
                    showError("Unsupported content type")
                }
            }
            else -> {
                Log.w(TAG, "Unhandled action: ${intent.action}")
                showError("Unsupported action")
            }
        }
    }

    private fun handleSharedText(intent: Intent) {
        val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)

        if (sharedText.isNullOrBlank()) {
            Log.w(TAG, "Shared text is null or blank")
            showError("No text content received")
            return
        }

        val sanitizedText = sanitizeText(sharedText)

        if (sanitizedText.isNullOrBlank()) {
            Log.w(TAG, "Text failed sanitization")
            showError("Invalid text content")
            return
        }

        // Check if the text contains a URL
        val extractedUrl = extractUrl(sanitizedText)

        if (extractedUrl != null) {
            if (validateUrl(extractedUrl)) {
                processSharedUrl(extractedUrl, sanitizedText)
            } else {
                Log.w(TAG, "URL failed validation: $extractedUrl")
                showError("Invalid URL received")
            }
        } else {
            processSharedPlainText(sanitizedText)
        }
    }

    private fun sanitizeText(text: String): String? {
        if (text.length > MAX_TEXT_LENGTH) {
            Log.w(TAG, "Text exceeds maximum length: ${text.length}")
            return null
        }

        // Remove null bytes and control characters (except newline, tab, carriage return)
        val sanitized = text.replace(Regex("[\\x00-\\x08\\x0B\\x0C\\x0E-\\x1F\\x7F]"), "")
            .trim()

        // Check for potential script injection
        if (containsScriptInjection(sanitized)) {
            Log.w(TAG, "Potential script injection detected in text")
            return null
        }

        return sanitized
    }

    private fun containsScriptInjection(text: String): Boolean {
        val lowerText = text.lowercase()
        val dangerousPatterns = listOf(
            "<script",
            "javascript:",
            "vbscript:",
            "data:text/html",
            "onclick=",
            "onerror=",
            "onload=",
            "intent://",
            "intent:#Intent"
        )
        return dangerousPatterns.any { lowerText.contains(it) }
    }

    private fun extractUrl(text: String): String? {
        val matcher = Patterns.WEB_URL.matcher(text)
        return if (matcher.find()) {
            matcher.group()
        } else {
            null
        }
    }

    private fun validateUrl(url: String): Boolean {
        if (url.length > MAX_URL_LENGTH) {
            Log.w(TAG, "URL exceeds maximum length")
            return false
        }

        if (!Patterns.WEB_URL.matcher(url).matches()) {
            Log.w(TAG, "URL does not match web URL pattern")
            return false
        }

        return try {
            val parsedUrl = URL(url)
            val scheme = parsedUrl.protocol?.lowercase()

            // Only allow http and https schemes
            if (scheme != "http" && scheme != "https") {
                Log.w(TAG, "Disallowed URL scheme: $scheme")
                return false
            }

            val host = parsedUrl.host
            if (host.isNullOrBlank()) {
                Log.w(TAG, "URL has no host")
                return false
            }

            // Block localhost and private IPs to prevent SSRF
            if (isPrivateOrLocalHost(host)) {
                Log.w(TAG, "URL points to private/local address: $host")
                return false
            }

            true
        } catch (e: Exception) {
            Log.w(TAG, "URL parsing failed: ${e.message}")
            false
        }
    }

    private fun isPrivateOrLocalHost(host: String): Boolean {
        val lowerHost = host.lowercase()
        return lowerHost == "localhost" ||
                lowerHost == "127.0.0.1" ||
                lowerHost == "::1" ||
                lowerHost == "0.0.0.0" ||
                lowerHost.startsWith("10.") ||
                lowerHost.startsWith("192.168.") ||
                lowerHost.matches(Regex("172\\.(1[6-9]|2[0-9]|3[0-1])\\..*")) ||
                lowerHost.endsWith(".local") ||
                lowerHost.endsWith(".internal")
    }

    private fun handleSharedImage(intent: Intent) {
        val imageUri: Uri? = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            intent.getParcelableExtra(Intent.EXTRA_STREAM, Uri::class.java)
        } else {
            @Suppress("DEPRECATION")
            intent.getParcelableExtra(Intent.EXTRA_STREAM)
        }

