        }

        if (validUris.isEmpty()) {
            Log.w(TAG, "No valid image URIs after validation")
            showError("No valid images received")
            return
        }

        processSharedMultipleImages(validUris)
    }

    private fun validateUri(uri: Uri): Boolean {
        val scheme = uri.scheme?.lowercase()

        if (scheme == null || scheme !in ALLOWED_URI_SCHEMES) {
            Log.w(TAG, "Disallowed URI scheme: $scheme")
            return false
        }

        // Prevent path traversal
        val path = uri.path ?: ""
        if (path.contains("..") || path.contains("//")) {
            Log.w(TAG, "Potential path traversal in URI: $path")
            return false
        }

        // Check that we can actually read the URI
        return try {
            val inputStream: InputStream? = contentResolver.openInputStream(uri)
            inputStream?.close()
            true
        } catch (e: SecurityException) {
            Log.w(TAG, "SecurityException reading URI: ${e.message}")
            false
        } catch (e: Exception) {
            Log.w(TAG, "Cannot read URI: ${e.message}")
            false
        }
    }

    private fun validateImageMimeType(uri: Uri): Boolean {
        val mimeType = contentResolver.getType(uri)?.lowercase()

        if (mimeType == null) {
            Log.w(TAG, "Cannot determine MIME type for URI")
            return false
        }

        if (mimeType !in ALLOWED_IMAGE_MIME_TYPES) {
            Log.w(TAG, "Disallowed image MIME type: $mimeType")
            return false
        }

        // Validate file size
        return try {
            contentResolver.openInputStream(uri)?.use { inputStream ->
                val bytes = inputStream.readBytes()
                if (bytes.size > MAX_IMAGE_SIZE_BYTES) {
                    Log.w(TAG, "Image too large: ${bytes.size} bytes")
                    return false
                }

                // Validate that the content is actually an image by trying to decode bounds
                val options = BitmapFactory.Options().apply {
                    inJustDecodeBounds = true
                }
                BitmapFactory.decodeByteArray(bytes, 0, bytes.size, options)

                if (options.outWidth <= 0 || options.outHeight <= 0) {
                    Log.w(TAG, "Content is not a valid image (decode failed)")
                    return false
                }

                true
            } ?: false
        } catch (e: Exception) {
            Log.w(TAG, "Error validating image: ${e.message}")
            false
        }
    }

