        }
    }

    private fun processSharedMultipleImages(uris: List<Uri>) {
        Log.i(TAG, "Processing ${uris.size} shared images")

        addTextView("${uris.size} Shared Images Received")

        uris.forEachIndexed { index, uri ->
            try {
                contentResolver.openInputStream(uri)?.use { inputStream ->
                    val bitmap = BitmapFactory.decodeStream(inputStream)
                    if (bitmap != null) {
                        addTextView("Image ${index + 1}:")

                        val imageView = ImageView(this).apply {
