                        containerLayout.addView(imageView)

                        addTextView("Size: ${bitmap.width} x ${bitmap.height}")
                    }
                }
            } catch (e: Exception) {
                Log.e(TAG, "Error processing image $index: ${e.message}")
                addTextView("Image ${index + 1}: Error loading")
            }
        }

        Toast.makeText(this, "${uris.size} images received", Toast.LENGTH_SHORT).show()

        // TODO: Implement your multiple image processing logic here
    }

